// src/components/HomePage.js
import React from "react";
import { Link } from "react-router-dom";

const serviceData = [
  {
    path: "/image",
    title: "Image Deepfake Detector",
    icon: "🖼️",
    description: "Upload images to check for AI manipulation (e.g., FaceSwap).",
  },
  {
    path: "/video",
    title: "Video Deepfake Detector",
    icon: "🎥",
    description: "Analyze video frames for subtle signs of digital alteration.",
  },
  {
    path: "/audio",
    title: "Audio Deepfake Detector",
    icon: "🎤",
    description:
      "Check audio clips for synthetic voice generation (e.g., cloned voices).",
  },
  {
    path: "/misinformation",
    title: "Misinformation Checker",
    icon: "📰",
    description:
      "Paste text/articles to check for factual accuracy using Gemini AI.",
  },
  {
    path: "/chatbot",
    title: "Project Chatbot",
    icon: "🤖",
    description:
      "Ask the Gemini-powered assistant questions about this project.",
  },
];

function HomePage() {
  const gridStyle = {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
    gap: "20px",
    marginTop: "30px",
  };

  const iconStyle = {
    fontSize: "3em",
    marginBottom: "10px",
  };

  return (
    <div>
      <h2 style={{ textAlign: "center", color: "#34495e" }}>
        Select a Deepfake or Misinformation Service
      </h2>
      <p style={{ textAlign: "center", color: "#7f8c8d" }}>
        Click on any card to access the dedicated analysis tool.
      </p>

      <div style={gridStyle}>
        {serviceData.map((service) => (
          <Link key={service.path} to={service.path} className="service-card">
            <div style={iconStyle}>{service.icon}</div>
            <h3>{service.title}</h3>
            <p style={{ color: "#7f8c8d", fontSize: "0.9em" }}>
              {service.description}
            </p>
          </Link>
        ))}
      </div>
    </div>
  );
}

export default HomePage;
